    $content = @"
---
pub-id: $pubId
type:
    - patent
year: $($patents[$i].Year)
title: "$($patents[$i].Title)"
title_url: ""
authors: "$($patents[$i].Authors)"
status: $($patents[$i].Status)
venue: "$($patents[$i].Venue)"
---
"@
    Set-Content -Path $filename -Value $content -Encoding UTF8
    Write-Host "Created $filename"
}
